    if (!match(I.getOperand(1 - ShOpnum),
               m_BinOp(m_Value(ShiftedX), m_Value(Mask))))
      return nullptr;

    if (!match(ShiftedX, m_OneUse(m_Shift(m_Value(X), m_Specific(Shift)))))
      return nullptr;

    // Make sure we are matching instruction shifts and not ConstantExpr
    auto *IY = dyn_cast<Instruction>(I.getOperand(ShOpnum));
    auto *IX = dyn_cast<Instruction>(ShiftedX);
    if (!IY || !IX)
      return nullptr;

    // LHS and RHS need same shift opcode
    unsigned ShOpc = IY->getOpcode();
    if (ShOpc != IX->getOpcode())
      return nullptr;

    // Make sure binop is real instruction and not ConstantExpr
    auto *BO2 = dyn_cast<Instruction>(I.getOperand(1 - ShOpnum));
    if (!BO2)
      return nullptr;

    // We are looking for: (X << Sh) ^ (Y << Sh) ^ Z  -->  (X ^ Y) << Sh ^ Z
    if (BO2->getOpcode() != I.getOpcode())
      return nullptr;

    // The binop should be an xor (same as outer)
    if (I.getOpcode() != Instruction::Xor)
      return nullptr;

    // Avoid introducing UB: ensure shift amount is valid
    if (auto *CShift = dyn_cast<ConstantInt>(Shift))
      if (CShift->getValue().uge(8)) // for i8
        return nullptr;

    // Create new XOR of the base values
    Value *NewXor = Builder->CreateXor(X, Y, "xory");
    // Shift the combined XOR
    Value *NewShifted = Builder->CreateShl(NewXor, Shift, "shl");
    // XOR with the outer mask
    Value *NewXor2 = Builder->CreateXor(NewShifted, Mask, "r");

    // Replace and return the final instruction
    I.replaceAllUsesWith(NewXor2);
    return &I;
  };
